import{app}from"./firebase.min.js";import{getFirestore,doc,setDoc,updateDoc,getDoc,collection,addDoc,query,orderBy,limit,getDocs,serverTimestamp,deleteDoc,runTransaction}from"https://www.gstatic.com/firebasejs/12.1.0/firebase-firestore.js";const db=getFirestore(app);let currentChatDocId=null;export function getCurrentChatDocId(){return currentChatDocId}export function setCurrentChatDocId(e){currentChatDocId=e||null}export function resetCurrentChatDoc(){currentChatDocId=null}export function generateChatTitle(e=""){let t=e.trim().toLowerCase();if(!t)return"Conversation";t=t.replace(/please|can you|help me|i want|i need|i am|i'm|could you|would you|tell me|explain|show me/gi,""),t=t.trim();const r=t.split(/\s+/).filter(Boolean);if(r.length<3)return"Conversation";let a=r.slice(0,6).join(" ");return a=a.replace(/[^\w\s]/g,""),a.charAt(0).toUpperCase()+a.slice(1)}export async function saveChatToHistory(e,t,r,a=!1,o={}){try{if(!e)return null;const{mode:s="chat",metadata:n={},chatId:c=null}=o,i=collection(db,"history",e,"chats"),l=Date.now(),d={sender:"user",text:t||"",createdAt:l,mode:s,metadata:n},u={sender:"ai",text:r||"",createdAt:l,mode:s,metadata:n};if(a||!c){const e=generateChatTitle(t);return(await addDoc(i,{title:e,messages:[d,u],createdAt:serverTimestamp(),updatedAt:serverTimestamp(),lastMode:s})).id}const h=doc(db,"history",e,"chats",c);return await runTransaction(db,async e=>{const r=await e.get(h);if(!r.exists())return e.set(h,{title:generateChatTitle(t),messages:[d,u],createdAt:serverTimestamp(),updatedAt:serverTimestamp(),lastMode:s}),c;const a=r.data(),o=Array.isArray(a.messages)?a.messages:[],n=a.title,i=!n||"Conversation"===n||n.trim().length<10;return e.update(h,{messages:[...o,d,u],updatedAt:serverTimestamp(),lastMode:s,...i&&{title:generateChatTitle(d.text)}}),c})}catch(e){return console.error("🔥 Error saving chat:",e),null}}export async function getLatestChat(e){try{if(!e)return null;const t=collection(db,"history",e,"chats"),r=query(t,orderBy("createdAt","desc"),limit(1)),a=await getDocs(r);if(!a.empty){const e=a.docs[0];return currentChatDocId=e.id,{chatId:e.id,messages:e.data().messages||[]}}return currentChatDocId=null,null}catch(e){return console.error("🔥 Error retrieving latest chat:",e),currentChatDocId=null,null}}export async function saveFullChatSession(e,t){if(e&&t&&0!==t.length)try{const r=t.find(e=>"user"===e.sender)?.text||"Conversation",a=r.length>30?r.slice(0,30)+"...":r,o=doc(collection(db,"history",e,"sessions"));await setDoc(o,{title:a,messages:t,createdAt:serverTimestamp()}),console.log("✅ Chat session saved:",a)}catch(e){console.error("❌ Failed to save full chat session:",e)}}export async function getAllChats(e){try{if(!e)return console.warn("⚠️ No userId provided to getAllChats()"),[];const t=collection(db,"history",e,"chats"),r=query(t,orderBy("createdAt","desc")),a=await getDocs(r);return a.docs.map(e=>({id:e.id,...e.data()}))}catch(e){return console.error("🔥 Error fetching chats:",e),[]}}export async function getChatById(e,t){if(!e||!t)return console.error("❌ Missing userUID or chatId"),null;try{const r=doc(db,"history",e,"chats",t),a=await getDoc(r);if(!a.exists())return console.warn("⚠️ No such chat:",t),null;const o=a.data(),s=(o.messages||[]).map(e=>({role:"user"===e.sender?"user":"ai",content:e.text||"",mode:e.mode||"chat",metadata:e.metadata||{},createdAt:"number"==typeof e.createdAt?e.createdAt:e.createdAt?.toMillis?e.createdAt.toMillis():null}));return{id:t,...o,messages:s}}catch(e){return console.error("🔥 Error fetching chat by ID:",e),null}}export async function deleteChatHistory(e,t){if(e&&t)try{const r=doc(db,"history",e,"chats",t);await deleteDoc(r),console.log("🗑 Chat deleted:",t)}catch(e){console.error("❌ Failed to delete chat:",e)}}